import React, { useRef, useMemo } from "react";
import ReactECharts from "echarts-for-react";
import { theme as antdTheme } from "antd";

interface EChartProps {
  option: any;
  style?: React.CSSProperties;
  className?: string;
  theme?: "light" | "dark" | string;
  notMerge?: boolean;
  lazyUpdate?: boolean;
  loading?: boolean;
  onEvents?: Record<string, Function>;
  onChartReady?: (instance: any) => void;
}

/**
 * Common Smart EChart Component.
 * Automatically integrates with the framework's theme system (Palette, Typography, Grid).
 */
export default function EChart({
  option,
  style = { height: "300px", width: "100%" },
  className,
  theme,
  notMerge = false,
  lazyUpdate = false,
  loading = false,
  onEvents,
  onChartReady,
}: EChartProps) {
  const chartRef = useRef<ReactECharts>(null);
  const { token } = antdTheme.useToken();
  
  // Framework Custom Theme Token Access (Casting as any since antd doesn't know about 'chart' key yet)
  const chartTheme = (token as any).chart || {
    palette: ["#2563EB", "#10B981", "#F59E0B", "#EF4444", "#3B82F6"],
    gridColor: "rgba(0,0,0,0.05)",
    axisLabelColor: "#666",
    tooltipBg: "rgba(255,255,255,0.9)",
  };

  const isDark = token.colorBgContainer.includes("rgb(31, 31, 31)") || token.colorBgContainer.includes("#1f");

  const mergedOption = useMemo(() => {
    return {
      // 1. Apply Framework Palette
      color: chartTheme.palette,
      
      backgroundColor: "transparent",
      
      // 2. Global Typography Sync
      textStyle: {
        fontFamily: token.fontFamily,
        color: token.colorText,
      },

      // 3. Coordinate System Styling
      grid: {
        left: "3%",
        right: "4%",
        bottom: "3%",
        containLabel: true,
        borderColor: chartTheme.gridColor,
      },
      
      xAxis: {
        axisLine: { lineStyle: { color: token.colorBorderSecondary } },
        axisLabel: { color: chartTheme.axisLabelColor, fontSize: 11 },
        splitLine: { show: false },
      },
      
      yAxis: {
        axisLine: { show: false },
        axisLabel: { color: chartTheme.axisLabelColor, fontSize: 11 },
        splitLine: { lineStyle: { color: chartTheme.gridColor, type: "dashed" } },
      },

      // 4. Tooltip & Legend Styling
      tooltip: {
        trigger: "axis",
        backgroundColor: chartTheme.tooltipBg,
        borderColor: token.colorBorderSecondary,
        borderWidth: 1,
        textStyle: { color: token.colorText, fontSize: 13 },
        ...option?.tooltip,
        confine: true, // Force confine within container to avoid being cut off
      },
      
      legend: {
        textStyle: { color: token.colorTextSecondary, fontSize: 12 },
        icon: "circle",
        ...option?.legend,
      },

      ...option,
    };
  }, [option, token, chartTheme]);

  return (
    <div className={className} style={style}>
      <ReactECharts
        ref={chartRef}
        option={mergedOption}
        notMerge={notMerge}
        lazyUpdate={lazyUpdate}
        showLoading={loading}
        onEvents={onEvents}
        onChartReady={onChartReady}
        theme={theme || (isDark ? "dark" : "light")}
        style={{ height: "100%", width: "100%" }}
      />
    </div>
  );
}
